        emit WhitelistUpdated(user, status);
    }

    function toggleSale() public onlyOwner {
        if (currentState == State.SaleClosed) {
            revert("Sale is already closed");
        }
        currentState = currentState == State.PresaleLive ? State.SaleLive : State.SaleClosed;
        emit SaleToggled(currentState);
    }

